SELECT g.*, ste.site_nm AS site_nm, cd_mg.code_label AS grade_cd_nm FROM mb_member_grade g LEFT JOIN sy_site ste ON ste.site_id = g.site_id LEFT JOIN sy_code cd_mg ON cd_mg.code_grp = 'MEMBER_GRADE' AND cd_mg.code_value = g.grade_cd
ORDER BY g.grade_id ASC ORDER BY g.grade_id DESC ORDER BY g.grade_nm ASC ORDER BY g.grade_nm DESC ORDER BY g.reg_date ASC ORDER BY g.reg_date DESC ORDER BY g.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

