ORDER BY g.grade_id ASC ORDER BY g.grade_id DESC ORDER BY g.grade_nm ASC ORDER BY g.grade_nm DESC ORDER BY g.reg_date ASC ORDER BY g.reg_date DESC ORDER BY g.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

mapper.update:
UPDATE mb_member_grade
site_id = #{siteId}, grade_cd = #{gradeCd}, grade_nm = #{gradeNm}, grade_rank = #{gradeRank}, min_purchase_amt = #{minPurchaseAmt}, save_rate = #{saveRate}, use_yn = #{useYn}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE grade_id = #{gradeId}
